276	// legacySkillSymlinkDirs returns the relative names of skill directories
277	// (e.g. ".agents/skills", ".claude/skills") under workingDir that contain
278	// at least one symlink. A symlink indicates a pre-FEAT-015 install.
279	func legacySkillSymlinkDirs(workingDir string) []string {
280		if workingDir == "" {
281			return nil
282		}
283		var found []string
284		for _, rel := range []string{".agents/skills", ".claude/skills"} {
285			dir := filepath.Join(workingDir, rel)
286			entries, err := os.ReadDir(dir)
287			if err != nil {
288				continue
289			}
290			for _, e := range entries {
291				info, err := e.Info()
292				if err != nil {
293					continue
294				}
295				if info.Mode()&os.ModeSymlink != 0 {
296					found = append(found, rel)
297					break
298				}
299			}
300		}
301		return found
302	}
