304	// checkBinaryInstallLocation verifies the running binary is at the canonical install
305	// location ($HOME/.local/bin/ddx) and scans PATH for other ddx copies whose
306	// SHA-256 differs from the running binary.
307	func checkBinaryInstallLocation(executable string) []DiagnosticIssue {
308		var issues []DiagnosticIssue
309	
310		homeDir, err := os.UserHomeDir()
311		if err != nil {
312			return issues
313		}
314	
315		canonicalPath := filepath.Join(homeDir, ".local", "bin", "ddx")
316	
317		// (2) Check whether running binary matches the canonical install location.
318		resolvedExec, _ := filepath.EvalSymlinks(executable)
319		if resolvedExec == "" {
320			resolvedExec = executable
321		}
322		resolvedCanonical, _ := filepath.EvalSymlinks(canonicalPath)
323		execMatchesCanonical := resolvedExec == canonicalPath ||
324			(resolvedCanonical != "" && resolvedExec == resolvedCanonical)
325		if !execMatchesCanonical {
326			issues = append(issues, DiagnosticIssue{
327				Type:        "binary_not_canonical",
328				Description: fmt.Sprintf("Running binary (%s) is not at canonical install location (%s)", executable, canonicalPath),
329				Remediation: []string{
330					"Re-run install.sh to reinstall to the canonical location",
331					fmt.Sprintf("Or ensure %s is earlier in your PATH", filepath.Dir(canonicalPath)),
332				},
333			})
334		}
335	
336		// (3) Walk PATH and flag any ddx copy whose SHA-256 differs from the running binary.
337		runningSHA, err := computeFileSHA256(executable)
338		if err != nil {
339			return issues
340		}
341	
342		seen := make(map[string]bool)
343		for _, dir := range filepath.SplitList(os.Getenv("PATH")) {
344			candidate := filepath.Join(dir, "ddx")
345			if seen[candidate] {
346				continue
347			}
348			seen[candidate] = true
349	
350			info, err := os.Stat(candidate)
351			if err != nil || !info.Mode().IsRegular() || info.Mode()&0111 == 0 {
352				continue
353			}
354	
355			candidateSHA, err := computeFileSHA256(candidate)
356			if err != nil {
357				continue
358			}
359	
360			if candidateSHA == runningSHA {
361				continue // same binary, not stale
362			}
363	
364			issues = append(issues, DiagnosticIssue{
365				Type:        "binary_sha_mismatch",
366				Description: fmt.Sprintf("Stale ddx copy on PATH: %s (SHA-256 differs from running binary)", candidate),
367				Remediation: []string{
368					fmt.Sprintf("rm %s && cp %s %s", candidate, executable, candidate),
369					"Or re-run install.sh to update all copies",
370				},
371			})
372		}
373	
374		return issues
375	}
