377	// computeFileSHA256 returns the hex-encoded SHA-256 digest of the named file.
378	func computeFileSHA256(path string) (string, error) {
379		f, err := os.Open(path)
380		if err != nil {
381			return "", err
382		}
383		defer f.Close()
384	
385		h := sha256.New()
386		if _, err := io.Copy(h, f); err != nil {
387			return "", err
388		}
389		return hex.EncodeToString(h.Sum(nil)), nil
390	}
