561		state, err := registry.LoadState()
562		if err != nil || len(state.Installed) == 0 {
563			return
564		}
565	
566		reg := registry.BuiltinRegistry()
567		for _, entry := range state.Installed {
568			pkg, err := reg.Find(entry.Name)
569			if err != nil || pkg.Install.Scripts == nil {
570				continue
571			}
572	
573			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
574			name := filepath.Base(dst)
575			fmt.Printf("✓ Checking %s launcher... ", name)
576	
577			li, err := os.Lstat(dst)
578			if os.IsNotExist(err) {
579				fmt.Printf("❌ MISSING (%s not found, run: ddx install %s)\n", dst, pkg.Name)
580				continue
581			}
582			if err != nil {
583				fmt.Printf("❌ error: %v\n", err)
584				continue
585			}
586	
587			if li.Mode()&os.ModeSymlink != 0 {
588				target, _ := os.Readlink(dst)
589				if verbose {
590					fmt.Printf("✅ OK (developer symlink → %s)\n", target)
591				} else {
592					fmt.Println("✅ OK (developer symlink)")
593				}
594				continue
595			}
596	
597			// Regular file — check it's executable.
598			if li.Mode()&0111 != 0 {
599				fmt.Printf("✅ OK (%s)\n", dst)
600			} else {
601				fmt.Printf("⚠️  not executable (run: chmod +x %s)\n", dst)
