606	// checkInstalledPlugins audits installed plugin roots and manifests.
607	func checkInstalledPlugins(verbose bool) []DiagnosticIssue {
608		state, err := registry.LoadState()
609		if err != nil || len(state.Installed) == 0 {
610			return nil
611		}
612	
613		reg := registry.BuiltinRegistry()
614		var issues []DiagnosticIssue
615	
616		for _, entry := range state.Installed {
617			fallback, _ := reg.Find(entry.Name)
618			entryType := entry.Type
619			if entryType == "" && fallback != nil {
620				entryType = fallback.Type
621			}
622			if entryType == "" && !looksLikePluginInstall(entry) {
623				continue
624			}
625			switch entryType {
626			case registry.PackageTypePlugin, registry.PackageTypeWorkflow:
627			case "":
628			default:
629				continue
630			}
631			for _, issue := range registry.AuditInstalledEntry(entry, fallback) {
632				diag := DiagnosticIssue{
633					Type:        "plugin_validation",
634					Description: issue.Error(),
635					Remediation: []string{
636						"Check package.yaml, skill directories, and installed symlinks for the path shown above",
637						"Reinstall the package after fixing the source tree or manifest",
638					},
639					SystemInfo: map[string]string{
640						"plugin": entry.Name,
641					},
642				}
643				if verbose {
644					diag.SystemInfo["source"] = entry.Source
645				}
646				issues = append(issues, diag)
647			}
648		}
649	
650		return issues
651	}
