686	// checkGitRepoHealth detects git-repo corruption from prior ddx incidents:
687	//  1. core.bare=true on a repo that has a working tree (not actually bare)
688	//  2. Stray core.worktree that does not match the actual toplevel
689	//  3. extensions.worktreeConfig not enabled (warning only)
690	//
691	// If fix is true, conditions (1) and (2) are remediated with `git config --unset`.
692	// (3) is always a warning — never auto-fixed, since enabling per-worktree config
693	// is a user-facing choice.
694	func checkGitRepoHealth(workingDir string, fix bool) []DiagnosticIssue {
695		var issues []DiagnosticIssue
696		ctx := context.Background()
697	
698		// Bail out quietly if this directory isn't a git repo at all. We can't rely
699		// on `--is-inside-work-tree` here because the corruption we're looking for
700		// (core.bare=true on a repo that has a working tree) causes git to report
701		// "false" for that query. Instead, probe `--git-dir`, which succeeds on both
702		// bare and non-bare repos.
703		gitDirProbe := gitpkg.Command(ctx, workingDir, "rev-parse", "--git-dir")
704		gdOut, err := gitDirProbe.Output()
705		if err != nil {
706			return nil
707		}
708		gitDirRaw := strings.TrimSpace(string(gdOut))
709		if gitDirRaw == "" {
710			return nil
711		}
712	
713		// A "real" working tree on disk: either .git is a directory/file at
714		// workingDir, or git reports a separate work-tree via --show-toplevel.
715		// If neither holds, this is a genuinely bare repo → skip the checks.
716		hasWorkTreeOnDisk := false
717		if _, statErr := os.Stat(filepath.Join(workingDir, ".git")); statErr == nil {
718			hasWorkTreeOnDisk = true
719		}
720		if !hasWorkTreeOnDisk {
721			// Maybe we're inside a linked worktree where git treats us normally.
722			inWT := gitpkg.Command(ctx, workingDir, "rev-parse", "--is-inside-work-tree")
723			if b, err := inWT.Output(); err == nil && strings.TrimSpace(string(b)) == "true" {
724				hasWorkTreeOnDisk = true
725			}
726		}
727		if !hasWorkTreeOnDisk {
728			return nil
729		}
730	
731		gitConfigValue := func(key string) (string, bool) {
732			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--get", key)
733			b, err := c.Output()
734			if err != nil {
735				return "", false
736			}
737			return strings.TrimSpace(string(b)), true
738		}
739		gitConfigUnset := func(key string) error {
740			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--unset", key)
741			return c.Run()
742		}
743	
744		// (1) core.bare=true on a repo with a working tree → corruption.
745		if val, ok := gitConfigValue("core.bare"); ok && val == "true" {
746			desc := "core.bare=true is set on a repository that has a working tree (not actually bare)"
747			rem := []string{"git config --unset core.bare"}
748			if fix {
749				if err := gitConfigUnset("core.bare"); err == nil {
750					desc += " — removed"
751				} else {
752					desc += fmt.Sprintf(" — unset failed: %v", err)
753				}
754			}
755			issues = append(issues, DiagnosticIssue{
756				Type:        "git_core_bare_corruption",
757				Description: desc,
758				Remediation: rem,
759			})
760		}
761	
762		// (2) Stray core.worktree that doesn't match the directory we're running
763		// against. Compare to workingDir directly — asking git for --show-toplevel
764		// would just echo back core.worktree.
765		if worktreeVal, ok := gitConfigValue("core.worktree"); ok && worktreeVal != "" {
766			actual := workingDir
767	
768			cmpVal := worktreeVal
769			if !filepath.IsAbs(cmpVal) {
770				cmpVal = filepath.Clean(filepath.Join(gitDirRaw, worktreeVal))
771			}
772			resolvedCmp, _ := filepath.EvalSymlinks(cmpVal)
773			if resolvedCmp == "" {
774				resolvedCmp = cmpVal
775			}
776			resolvedActual, _ := filepath.EvalSymlinks(actual)
777			if resolvedActual == "" {
778				resolvedActual = actual
779			}
780	
781			if actual != "" && resolvedCmp != resolvedActual {
782				desc := fmt.Sprintf("core.worktree=%q does not match actual worktree %q", worktreeVal, actual)
783				rem := []string{"git config --unset core.worktree"}
784				if fix {
785					if err := gitConfigUnset("core.worktree"); err == nil {
786						desc += " — removed"
787					} else {
788						desc += fmt.Sprintf(" — unset failed: %v", err)
789					}
790				}
791				issues = append(issues, DiagnosticIssue{
792					Type:        "git_stray_core_worktree",
793					Description: desc,
794					Remediation: rem,
795				})
796			}
797		}
798	
799		// (3) extensions.worktreeConfig not enabled → warning only.
800		val, ok := gitConfigValue("extensions.worktreeConfig")
801		if !ok || val != "true" {
802			issues = append(issues, DiagnosticIssue{
803				Type:        "git_worktree_config_disabled",
804				Description: "extensions.worktreeConfig is not enabled; per-worktree config changes can corrupt the shared .git/config",
805				Remediation: []string{
806					"git config extensions.worktreeConfig true",
807				},
808			})
809		}
810	
811		return issues
812	}
