116	// initProject is the pure business logic function for project initialization
117	func initProject(workingDir string, opts InitOptions) (*InitResult, error) {
118		result := &InitResult{}
119	
120		// Validate git repository unless --no-git flag is used
121		if !opts.NoGit {
122			if err := validateGitRepo(workingDir); err != nil {
123				return nil, NewExitError(1, err.Error())
124			}
125		}
126	
127		// Guard against running inside an execute-bead context.
128		if os.Getenv("DDX_EXECUTE_BEAD_ID") != "" {
129			return nil, NewExitError(1,
130				"ddx init cannot be run inside an execute-bead context (DDX_EXECUTE_BEAD_ID is set)")
131		}
132		// Guard against running inside an execute-bead worktree. These are isolated
133		// execution environments under .ddx/.execute-bead-wt-*; running ddx init
134		// inside one would overwrite the project's .ddx/ config and beads.jsonl.
135		if isExecuteBeadWorktree(workingDir) {
136			return nil, NewExitError(1,
137				"ddx init cannot be run inside an execute-bead worktree (.ddx/.execute-bead-wt-*)")
138		}
139	
140		// Guard against nested workspaces: if a parent directory already has a
141		// .ddx/ workspace, refuse to create a second one in a subdirectory.
142		// This prevents the split-tracker bug where commands from different
143		// directories operate on different .ddx/beads.jsonl files.
144		if parent := findParentDDxWorkspace(workingDir); parent != "" {
145			return nil, NewExitError(1, fmt.Sprintf(
146				".ddx/ workspace already exists at %s. "+
147					"DDx anchors to the git repository root; run commands from any directory.",
148				parent))
149		}
150	
151		// Check if config already exists
152		configPath := filepath.Join(workingDir, ".ddx", "config.yaml")
153		if _, err := os.Stat(configPath); err == nil {
154			if !opts.Force {
155				// Config exists and --force not used - exit code 2 per contract
156				return nil, NewExitError(2, ".ddx/config.yaml already exists. Use --force to overwrite.")
157			}
158			// With --force flag, we proceed to overwrite without backup
159		}
160	
161		// Check if library path exists using working directory
162		cfg, err := config.LoadWithWorkingDir(workingDir)
163		libraryExists := true
164		if err != nil || cfg.Library == nil || cfg.Library.Path == "" {
165			libraryExists = false
166		} else if _, err := os.Stat(filepath.Join(workingDir, cfg.Library.Path)); os.IsNotExist(err) {
167			libraryExists = false
168		}
169		result.LibraryExists = libraryExists
170	
171		// Create configuration with defaults
172		localConfig := createProjectConfig()
173	
174		// Apply default values (including repository settings)
175		localConfig.ApplyDefaults()
176	
177		// Add validation during creation
178		if err := validateConfiguration(localConfig); err != nil {
179			return nil, NewExitError(1, fmt.Sprintf("Configuration validation failed: %v", err))
180		}
181	
182		// Try to load existing config to preserve settings (even if library doesn't exist yet)
183		if cfg != nil && err == nil {
184			// Note: Version is NOT copied - always upgrade to current version via ApplyDefaults
185			// Copy library settings if they exist (unless overridden by flags)
186			if cfg.Library != nil && localConfig.Library != nil {
187				if cfg.Library.Path != "" {
188					localConfig.Library.Path = cfg.Library.Path
189				}
190				if cfg.Library.Repository != nil && localConfig.Library.Repository != nil {
191					// Only copy existing values if not overridden by flags
192					if opts.Repository == "" && cfg.Library.Repository.URL != "" {
193						localConfig.Library.Repository.URL = cfg.Library.Repository.URL
194					}
195					if opts.Branch == "" && cfg.Library.Repository.Branch != "" {
